queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?case_studies a :Case_Studies .
    ?case_studies p:Description ?description .
    BIND(?description AS ?o0)
  }
  UNION
  {
    ?interviews a :Interviews .
    ?interviews p:Description ?description .
    ?interviews p:Topic ?topic_f .
    FILTER(STR(?topic_f) = "Environmental Science")
    BIND(?description AS ?o0)
  }
}

